import bisect
class Solution:
    def maximizeGreatness(self, nums):
        avail = sorted(nums)
        count = 0
        for x in sorted(nums):
            idx = bisect.bisect_right(avail, x)
            if idx < len(avail):
                avail.pop(idx)
                count += 1
        return count

